/**
 * Tool Loop — iterative tool call execution for DirectProvider.
 *
 * Safety guards:
 * 1. Iteration limit (default 25)
 * 2. Repetition detection (same tool+args ≥3 times → break)
 * 3. Parallel tool execution (Promise.all for multi-tool responses)
 */
import { createHash } from "node:crypto";
import { existsSync } from "node:fs";
import { resolve, dirname } from "node:path";
import type { McpPool } from "./mcp-pool.js";
import { enrichCodegraphResult } from "./codegraph-enricher.js";

// ─── Types shared with adapters ────────────────────────────────────────────

export interface ChatMessage {
  role: "system" | "user" | "assistant" | "tool";
  content: string | ContentBlock[];
  tool_call_id?: string;
  tool_calls?: ToolCall[];
}

export interface ContentBlock {
  type: "text" | "tool_use" | "tool_result";
  text?: string;
  id?: string;
  name?: string;
  input?: Record<string, unknown>;
  tool_use_id?: string;
  content?: string;
  is_error?: boolean;
}

export interface ToolCall {
  id: string;
  type: "function";
  function: { name: string; arguments: string };
}

export interface ToolDef {
  type: "function";
  function: {
    name: string;
    description?: string;
    parameters: Record<string, unknown>;
  };
}

/** Adapter must implement this to be used by the tool loop. */
export interface LlmAdapter {
  chat(messages: ChatMessage[], opts: {
    tools?: ToolDef[];
    onText?: (chunk: string) => void;
    onThinking?: (chunk: string) => void;
  }): Promise<{ message: ChatMessage; stopReason: string }>;
}

// ─── Tool Loop ─────────────────────────────────────────────────────────────

export interface ToolLoopOptions {
  maxIterations?: number;
  /** Context window size — enables mid-loop overflow protection. */
  contextWindow?: number;
  /** Max chars per tool result (truncated if exceeded). Default: unlimited. */
  maxToolResultChars?: number;
  onText?: (chunk: string) => void;
  onThinking?: (chunk: string) => void;
  onToolStart?: (name: string, input: string) => void;
  onToolEnd?: (name: string, result: string, isError: boolean) => void;
}

const DEFAULT_MAX_ITERATIONS = 25;
const REPETITION_THRESHOLD = 3;
const RTK_ENABLED = ["true", "1"].includes(process.env.RTK_SHELL_REWRITE ?? "");

export async function runToolLoop(
  adapter: LlmAdapter,
  pool: McpPool,
  messages: ChatMessage[],
  tools: ToolDef[],
  opts: ToolLoopOptions = {},
): Promise<{ stopReason: string }> {
  const maxIter = opts.maxIterations ?? DEFAULT_MAX_ITERATIONS;
  const recentCalls: string[] = []; // hashes of recent tool calls

  for (let i = 0; i < maxIter; i++) {
    // Mid-loop context overflow protection: if messages exceed 85% of context window, break early
    if (opts.contextWindow) {
      const currentTokens = estimateMessagesTokens(messages);
      if (currentTokens > opts.contextWindow * 0.85) {
        console.warn(`[tool-loop] context overflow guard: ${currentTokens} tokens > 85% of ${opts.contextWindow} — breaking at iteration ${i}`);
        messages.push({
          role: "assistant",
          content: "[System: Context budget nearly exhausted. Summarize progress and respond now.]",
        });
        const final = await adapter.chat(messages, { onText: opts.onText, onThinking: opts.onThinking });
        messages.push(final.message);
        return { stopReason: "context_overflow" };
      }
    }

    const { message, stopReason } = await adapter.chat(messages, {
      tools,
      onText: opts.onText,
      onThinking: opts.onThinking,
    });

    messages.push(message);

    // Extract tool calls (OpenAI format)
    const toolCalls = message.tool_calls;
    if (!toolCalls || toolCalls.length === 0) {
      return { stopReason };
    }

    // Repetition detection
    for (const tc of toolCalls) {
      const hash = hashToolCall(tc.function.name, tc.function.arguments);
      recentCalls.push(hash);
    }
    if (detectRepetition(recentCalls)) {
      messages.push({
        role: "assistant",
        content: "[System: Tool call loop detected — same call repeated multiple times. Please summarize your progress and respond to the user.]",
      });
      // One more call without tools to get a text response
      const final = await adapter.chat(messages, { onText: opts.onText, onThinking: opts.onThinking });
      messages.push(final.message);
      return { stopReason: "tool_loop_break" };
    }

    // Execute tool calls (parallel for different servers, serial for same)
    const results = await executeToolCalls(toolCalls, pool, opts);

    // Append tool results
    for (const r of results) {
      messages.push({
        role: "tool",
        tool_call_id: r.id,
        content: r.output,
      });
    }

    // Project auto-detect: hint agent about CodeGraph index and AI.md
    const usedCodegraph = toolCalls.some(tc => tc.function.name.startsWith("codegraph_"));
    const { codegraph: cgProjects, aiMd: aiProjects } = detectProjectHints(toolCalls);
    const hints: string[] = [];

    if (!usedCodegraph && cgProjects.length > 0) {
      const paths = cgProjects.map(p => `"${p}"`).join(", ");
      hints.push(`CodeGraph index detected at ${paths}. Use codegraph_context/codegraph_impact instead of grep for call-chain analysis.`);
      for (const p of cgProjects) hintedCodegraph.add(p);
    }
    if (aiProjects.length > 0) {
      const paths = aiProjects.map(p => `${p}/AI.md`).join(", ");
      hints.push(`AI.md found at ${paths} — read it for project conventions before making changes.`);
      for (const p of aiProjects) hintedAiMd.add(p);
    }
    if (hints.length > 0) {
      messages.push({
        role: "assistant",
        content: `[System hint: ${hints.join(" | ")}]`,
      });
    }
  }

  // Hit iteration limit
  messages.push({
    role: "assistant",
    content: "[System: Maximum tool call iterations reached. Please summarize your progress.]",
  });
  const final = await adapter.chat(messages, { onText: opts.onText, onThinking: opts.onThinking });
  messages.push(final.message);
  return { stopReason: "max_iterations" };
}

// ─── Helpers ───────────────────────────────────────────────────────────────

function hashToolCall(name: string, args: string): string {
  return createHash("md5").update(`${name}:${args}`).digest("hex").slice(0, 12);
}

function detectRepetition(recent: string[]): boolean {
  if (recent.length < REPETITION_THRESHOLD) return false;
  const last = recent[recent.length - 1];
  let count = 0;
  for (let i = recent.length - 1; i >= 0 && i >= recent.length - 5; i--) {
    if (recent[i] === last) count++;
  }
  return count >= REPETITION_THRESHOLD;
}

interface ToolResult {
  id: string;
  output: string;
}

async function executeToolCalls(
  toolCalls: ToolCall[],
  pool: McpPool,
  opts: ToolLoopOptions,
): Promise<ToolResult[]> {
  const results: ToolResult[] = [];
  const maxChars = opts.maxToolResultChars;

  // Group by server to serialize calls to the same server
  // but parallelize across different servers
  const tasks = toolCalls.map(async (tc) => {
    const name = tc.function.name;
    let args: Record<string, unknown>;
    try {
      args = JSON.parse(tc.function.arguments);
    } catch {
      args = {};
    }

    opts.onToolStart?.(name, tc.function.arguments);

    // RTK auto-rewrite: prefix shell commands with `rtk` for compressed output
    if (RTK_ENABLED && name === "shell" && typeof args.command === "string") {
      args.command = applyRtkPrefix(args.command);
    }

    try {
      const result = await pool.callTool(name, args);

      // Codegraph enrichment: 附加 domain 資訊和 wiki 連結
      if (name.startsWith("codegraph_")) {
        const projectPath = args.projectPath as string | undefined;
        enrichCodegraphResult(result, projectPath);
      }

      let output = serializeToolResult(result.content);
      // Truncate tool output for context-constrained models
      if (maxChars && output.length > maxChars) {
        output = output.slice(0, maxChars) + `\n...[truncated, ${output.length - maxChars} chars omitted]`;
      }
      opts.onToolEnd?.(name, output.slice(0, 200), !!result.isError);
      return { id: tc.id, output };
    } catch (err) {
      const errMsg = `Error executing ${name}: ${(err as Error).message}`;
      opts.onToolEnd?.(name, errMsg, true);
      return { id: tc.id, output: errMsg };
    }
  });

  // Execute all in parallel (MCP SDK handles its own serialization per-connection)
  const settled = await Promise.all(tasks);
  results.push(...settled);
  return results;
}

function serializeToolResult(content: unknown[]): string {
  if (!Array.isArray(content)) return String(content);
  return content
    .map((block: any) => {
      if (block.type === "text") return block.text;
      return JSON.stringify(block);
    })
    .join("\n");
}


/** Prefix eligible shell commands with `rtk` for compressed output. Skip interactive/piped commands. */
function applyRtkPrefix(cmd: string): string {
  const trimmed = cmd.trimStart();
  // Already has rtk prefix
  if (trimmed.startsWith("rtk ")) return cmd;
  // Skip: piped chains, interactive commands, redirections
  if (/[|><]/.test(cmd)) return cmd;
  // Only rewrite known rtk-friendly commands
  const rtkCmds = ["git status", "git diff", "git log", "grep ", "cargo test", "npm test", "npx tsc"];
  if (rtkCmds.some((c) => trimmed.startsWith(c))) {
    return `rtk ${trimmed}`;
  }
  return cmd;
}

/** Rough token estimate for mid-loop overflow check. */
function estimateMessagesTokens(messages: ChatMessage[]): number {
  let chars = 0;
  for (const m of messages) {
    const c = m.content;
    chars += (typeof c === "string" ? c.length : JSON.stringify(c ?? "").length) + 10;
  }
  return Math.ceil(chars / 4);
}

// ─── Project auto-detect hints (CodeGraph + AI.md) ─────────────────────────

/** Projects where we already emitted a hint this loop (avoid spamming). */
const hintedCodegraph = new Set<string>();
const hintedAiMd = new Set<string>();

/**
 * Extract project root paths from tool call args (read/grep/glob paths).
 * Walk up to 3 levels from the path to find .codegraph/ or AI.md.
 */
function detectProjectHints(toolCalls: ToolCall[]): { codegraph: string[]; aiMd: string[] } {
  const cgFound: string[] = [];
  const aiFound: string[] = [];

  for (const tc of toolCalls) {
    if (tc.function.name.startsWith("codegraph_")) continue;

    let args: Record<string, unknown>;
    try { args = JSON.parse(tc.function.arguments); } catch { continue; }

    const candidates: string[] = [];
    if (typeof args.path === "string") candidates.push(args.path);
    if (typeof args.file_path === "string") candidates.push(args.file_path);
    if (typeof args.pattern === "string" && /^[A-Z]:[/\\]/.test(args.pattern)) candidates.push(args.pattern);
    if (Array.isArray(args.operations)) {
      for (const op of args.operations as any[]) {
        if (typeof op?.path === "string") candidates.push(op.path);
      }
    }

    for (const p of candidates) {
      let dir = resolve(p.replace(/\//g, "\\"));
      if (/\.\w+$/.test(dir)) dir = dirname(dir);
      for (let depth = 0; depth < 4; depth++) {
        const normalized = dir.replace(/\\/g, "/");
        if (!hintedCodegraph.has(normalized) && existsSync(resolve(dir, ".codegraph"))) {
          cgFound.push(normalized);
        }
        if (!hintedAiMd.has(normalized) && existsSync(resolve(dir, "AI.md"))) {
          aiFound.push(normalized);
        }
        // Stop walking if we found both at this level
        if (cgFound.includes(normalized) && aiFound.includes(normalized)) break;
        const parent = dirname(dir);
        if (parent === dir) break;
        dir = parent;
      }
    }
  }
  return { codegraph: [...new Set(cgFound)], aiMd: [...new Set(aiFound)] };
}

/** Reset hints between sessions (call on session start). */
export function resetCodegraphHints(): void {
  hintedCodegraph.clear();
  hintedAiMd.clear();
}

