constructor(private cfg: DirectProviderConfig) {
  super();
  this.name = cfg.type;
  this.adapter = this.createAdapter();
  this.contextWindow = resolveContextWindow(cfg.type, cfg.model);
}

private createAdapter(): LlmAdapter {
  if (this.cfg.type === "anthropic") {
    return new AnthropicAdapter({
      apiKey: this.cfg.apiKey,
      model: this.cfg.model,
      baseUrl: this.cfg.baseUrl || undefined,
    });
  }
  if (this.cfg.type === "local") {
    const llamaCppUrl = process.env.LLAMACPP_URL?.trim();
    if (llamaCppUrl) {
      // llama.cpp server: OpenAI-compatible /v1/chat/completions with <think> tag parsing
      console.log(`[direct] using llama.cpp server at ${llamaCppUrl}`);
      return new LlamaCppAdapter({ baseUrl: llamaCppUrl, model: this.cfg.model, timeoutMs: 300_000, contextWindow: this.contextWindow });
    }
    return new OllamaNativeAdapter({
      baseUrl: this.cfg.baseUrl.replace(/\/v1$/, ""), // strip /v1 suffix
      model: this.cfg.model,
      numCtx: Number(process.env.LOCAL_NUM_CTX) || 32768,
    });
  }
  return new OpenAICompatAdapter({
    baseUrl: this.cfg.baseUrl,
    apiKey: this.cfg.apiKey,
    model: this.cfg.model,
    numCtx: undefined,
  });
}

/** Initialize MCP connections and prepare tool schemas. Returns a session ID. */
async initialize(): Promise<string> {
  let configs = await loadMcpConfigs();
  if (this.cfg.mcpServerFilter) {
    const allow = new Set(this.cfg.mcpServerFilter);
    configs = Object.fromEntries(Object.entries(configs).filter(([k]) => allow.has(k)));
  }
  await this.pool.connectAll(configs, this.cfg.mcpEnv);

  // Convert MCP tool schemas to OpenAI function format
  this.tools = this.pool.listTools().map(mcpToToolDef);

  // Set system prompt
  if (this.cfg.systemPrompt) {
    this.messages.push({ role: "system", content: this.cfg.systemPrompt });
  }

  const sessionId = `direct-${Date.now()}`;
  console.log(`[direct] initialized "${this.name}" (${this.cfg.model}) — ${this.tools.length} tools from ${this.pool.size} MCP servers`);
  return sessionId;
}

async prompt(text: string): Promise<{ stopReason: string }> {
  if (this._closed) throw new Error("DirectProvider is closed");
  if (this._inflight) throw new Error("Prompt already in progress");
  this._inflight = true;

  try {
    this.messages.push({ role: "user", content: text });

    // Context compaction: prevent messages from exceeding model context window
    const isLocal = this.cfg.type === "local";
    const summarizer = await detectLlamaCpp()
      ? async (text: string) => localComplete(
          `Summarize this conversation concisely (keep key decisions, tool results, and user requests):\n\n${text.slice(0, 6000)}`,
          { maxTokens: 800 },
        )
      : undefined;
    await compactIfNeeded(this.messages, {
      contextWindow: this.contextWindow,
      threshold: isLocal ? 0.5 : 0.7,
      keepTurns: isLocal ? 3 : 5,
      summarize: summarizer,
    });

    const result = await runToolLoop(this.adapter, this.pool, this.messages, this.tools, {
      ...(this.cfg.type === "local" ? {
        maxIterations: 8,
        contextWindow: this.contextWindow,
      } : {}),
      onText: (chunk) => {
        this.emitUpdate("agent_message_chunk", { type: "text", text: chunk });
      },
      onThinking: (chunk) => {
        // Surface thinking text to user as blockquote during streaming.
        this.emitUpdate("agent_thought_chunk", { type: "text", text: chunk });
      },
      onToolStart: (name, input) => {
        this.emitUpdate("tool_call", { title: name });
      },
      onToolEnd: (name, output, isError) => {
        this.emitUpdate("tool_call_update", {
