1	/**
2	 * Event Log — 狀態轉移持久化記錄
3	 * 
4	 * 可查、可審計、可回放。30 天滾動清理。
5	 */
6	
7	import { appendFileSync, existsSync, readFileSync, writeFileSync, mkdirSync } from "fs";
8	import { dirname, join } from "path";
9	import { config } from "./config.js";
10	
11	// ─── Types ─────────────────────────────────────────────────────────────────
12	
13	export type EventType =
14	  | "session_start"
15	  | "session_end"
16	  | "goal_start"
17	  | "goal_step"
18	  | "goal_done"
19	  | "goal_cancel"
20	  | "specialist_spawn"
21	  | "specialist_done"
22	  | "scheduler_fire"
23	  | "tool_call"
24	  | "error";
25	
26	export interface StateEvent {
27	  ts: string;
28	  type: EventType;
29	  chatId?: number;
30	  userId?: number;
31	  payload: Record<string, unknown>;
32	}
33	
34	// ─── Config ────────────────────────────────────────────────────────────────
35	
36	const EVENT_LOG_PATH = join(config.memoryDir, "events.jsonl");
37	const RETENTION_DAYS = 30;
38	
39	// ─── Core Functions ────────────────────────────────────────────────────────
40	
41	/**
42	 * 寫入一筆 event
43	 */
44	export function logEvent(
45	  type: EventType,
46	  payload: Record<string, unknown> = {},
47	  opts: { chatId?: number; userId?: number } = {}
48	): void {
49	  const event: StateEvent = {
50	    ts: new Date().toISOString(),
51	    type,
52	    ...opts,
53	    payload,
54	  };
55	
56	  try {
57	    // 確保目錄存在
58	    const dir = dirname(EVENT_LOG_PATH);
59	    if (!existsSync(dir)) {
60	      mkdirSync(dir, { recursive: true });
61	    }
62	
63	    appendFileSync(EVENT_LOG_PATH, JSON.stringify(event) + "\n", "utf-8");
64	  } catch (err) {
65	    // Event log 失敗不應該影響主流程
66	    console.error("[event-log] Failed to write event:", err);
67	  }
68	}
69	
70	/**
71	 * 讀取最近 n 筆 events
72	 */
73	export function getRecentEvents(n: number = 50): StateEvent[] {
74	  if (!existsSync(EVENT_LOG_PATH)) return [];
75	
76	  try {
77	    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
78	    const lines = content.trim().split("\n").filter(Boolean);
79	    const events = lines
80	      .slice(-n)
81	      .map((line) => {
82	        try {
83	          return JSON.parse(line) as StateEvent;
84	        } catch {
85	          return null;
86	        }
87	      })
88	      .filter((e): e is StateEvent => e !== null);
89	
90	    return events;
91	  } catch {
92	    return [];
93	  }
94	}
95	
96	/**
97	 * 讀取特定類型的 events
98	 */
99	export function getEventsByType(type: EventType, n: number = 50): StateEvent[] {
100	  return getRecentEvents(n * 3).filter((e) => e.type === type).slice(-n);
101	}
102	
103	/**
104	 * 讀取特定 chat 的 events
105	 */
106	export function getEventsByChat(chatId: number, n: number = 50): StateEvent[] {
107	  return getRecentEvents(n * 3).filter((e) => e.chatId === chatId).slice(-n);
108	}
109	
110	/**
111	 * 滾動清理：刪除超過 RETENTION_DAYS 的 events
112	 * 
113	 * 建議在 /dream 時呼叫
114	 */
115	export function rotateEventLog(): { deleted: number; kept: number } {
116	  if (!existsSync(EVENT_LOG_PATH)) {
117	    return { deleted: 0, kept: 0 };
118	  }
119	
120	  try {
121	    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
122	    const lines = content.trim().split("\n").filter(Boolean);
123	
124	    const cutoff = new Date();
125	    cutoff.setDate(cutoff.getDate() - RETENTION_DAYS);
126	    const cutoffStr = cutoff.toISOString();
127	
128	    const kept: string[] = [];
129	    let deleted = 0;
130	
131	    for (const line of lines) {
132	      try {
133	        const event = JSON.parse(line) as StateEvent;
134	        if (event.ts >= cutoffStr) {
135	          kept.push(line);
136	        } else {
137	          deleted++;
138	        }
139	      } catch {
140	        // 無法解析的行直接丟棄
141	        deleted++;
142	      }
