// AB-3 smoke: observer transformer correctness.
//
// Covers AB-1 §8 matrix rows #1-6 (token stripping — independent of
// usageStore / goalStore). Later smokes in AB-8 cover #7-12.
//
// Tokens under test:
//   SEND_FILE  — existing, regression
//   SCHEDULE   — existing, regression (stub parsers)
//   ASK        — existing, regression
//   SKILL_USED — new (AB-1)
//   GOAL_DONE  — new (AB-1)
//
// Run: node scripts/check-observer-transformer.mjs
// Uses compiled dist/observerTransformer.js — run `tsc` first.

import {
  transform,
  extractSendFileTokens,
  extractAskTokens,
} from "../dist/observerTransformer.js";

const results = [];
function ok(name) {
  results.push({ name, pass: true });
  console.log(`[PASS] ${name}`);
}
function fail(name, detail) {
  results.push({ name, pass: false, detail });
  console.error(`[FAIL] ${name}: ${detail}`);
}
function eq(a, b) {
  return JSON.stringify(a) === JSON.stringify(b);
}

// Stub schedule parsers: only recognize "30m" as a 30-minute duration,
// everything else returns null. Enough to test SCHEDULE stripping.
const stubParsers = {
  parseDuration: (raw) => (raw === "30m" ? 30 * 60 * 1000 : null),
  parseAbsoluteTime: () => null,
  parseRecurrence: () => null,
  computeNextRunAt: () => null,
  now: () => 1_700_000_000_000, // fixed epoch for determinism
};

// ───────────────────────────────────────────────────────────────────────
// 1. Plain text, no tokens — unchanged
// ───────────────────────────────────────────────────────────────────────
{
  const r = transform("Hello world\nNo tokens here.");
  if (r.text === "Hello world\nNo tokens here." &&
      r.sendFiles.length === 0 &&
      r.skillUsages.length === 0 &&
      r.goalDone === null &&
      r.askTokens.length === 0 &&
      r.scheduleTokens.length === 0) {
    ok("1. plain text untouched");
  } else {
    fail("1. plain text untouched", JSON.stringify(r));
  }
}

