async function executeToolCalls(
  toolCalls: ToolCall[],
  pool: McpPool,
  opts: ToolLoopOptions,
  precedingTools: string[] = [],
): Promise<ToolResult[]> {
  const results: ToolResult[] = [];
  const maxChars = opts.maxToolResultChars;

  // Group by server to serialize calls to the same server
  // but parallelize across different servers
  const tasks = toolCalls.map(async (tc) => {
    const name = tc.function.name;
    let args: Record<string, unknown>;
    try {
      args = JSON.parse(tc.function.arguments);
    } catch {
      args = {};
    }

    // F5/BC-7：在 RTK rewrite 之前快照原始 args 供 observation（否則記到 "rtk git status"）。
    const origArgs = { ...args };

    opts.onToolStart?.(name, tc.function.arguments);

    // RTK auto-rewrite: prefix shell commands with `rtk` for compressed output
    if (RTK_ENABLED && name === "shell" && typeof args.command === "string") {
      args.command = applyRtkPrefix(args.command);
    }

    try {
      const result = await pool.callTool(name, args);

      // Codegraph enrichment: 附加 domain 資訊和 wiki 連結
      if (name.startsWith("codegraph_")) {
        const projectPath = args.projectPath as string | undefined;
        enrichCodegraphResult(result, projectPath);
      }

      let output = serializeToolResult(result.content);
      // Tier B rich observation（成功分支）。在「為 context 截斷」之前觀測——observer 自帶截斷。
      observeRich(opts, name, origArgs, output, !!result.isError, precedingTools);
      // Truncate tool output for context-constrained models
      if (maxChars && output.length > maxChars) {
        output = output.slice(0, maxChars) + `\n...[truncated, ${output.length - maxChars} chars omitted]`;
      }
      opts.onToolEnd?.(name, output.slice(0, 200), !!result.isError);
      return { id: tc.id, output };
    } catch (err) {
      const errMsg = `Error executing ${name}: ${(err as Error).message}`;
      // 致命#4：失敗 tool 也寫 rich（最有萃取價值的失敗模式），否則 Direct 失敗 tool seq/rich 雙漏。
      observeRich(opts, name, origArgs, errMsg, true, precedingTools);
      opts.onToolEnd?.(name, errMsg, true);
      return { id: tc.id, output: errMsg };
    }
  });

