// Tool-Usage Observer (Phase 1) smoke.
//
// Covers BC-1a / BC-2 / BC-5 / BC-6 / BC-7 / BC-8 from
// .claude-loop/artifacts/P1-design-spec.md §3.
//   BC-1  (Direct→只 rich 不 seq)：rich 側由 BC-1a 覆蓋；no-seq-for-direct 由 seq 寫入點
//         的 `activeProvider==="acp"` 守衛 by-construction 保證（applyUpdate 為 private，
//         不在 dist 易測範圍，故此處測守衛所依賴的 record/序列單元）。
//   BC-3/BC-4 為 Phase 2（analyzer），本輪不實作。
//
// Run: node scripts/check-tool-observer.mjs
// Uses compiled dist/* — run `npx tsc` first.

import { writeFileSync, readFileSync, existsSync, mkdirSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";

// ── 必須在 import dist 之前設好 env ──────────────────────────────────────
// RTK_ENABLED 是 tool-loop 的 module-level const（import 時定值）→ 先開。
process.env.RTK_SHELL_REWRITE = "1";
const OBS_DIR = join(tmpdir(), "tko-smoke");
if (existsSync(OBS_DIR)) rmSync(OBS_DIR, { recursive: true, force: true });
mkdirSync(OBS_DIR, { recursive: true });
const OBS_PATH = join(OBS_DIR, "observations.jsonl");
process.env.BRIDGE_OBSERVATIONS_PATH = OBS_PATH;

const { redactArgs, recordSeqObservation, appendToolName, TURN_MARKER } =
  await import("../dist/tool-observer.js");
const { runToolLoop } = await import("../dist/provider/tool-loop.js");

// ── harness ──────────────────────────────────────────────────────────────
const results = [];
const ok = (n) => { results.push({ n, pass: true }); console.log(`[PASS] ${n}`); };
const fail = (n, d) => { results.push({ n, pass: false, d }); console.error(`[FAIL] ${n}: ${d}`); };

function resetObs() { writeFileSync(OBS_PATH, "", "utf-8"); }
function readObs() {
  if (!existsSync(OBS_PATH)) return [];
  return readFileSync(OBS_PATH, "utf-8").trim().split("\n").filter(Boolean).map((l) => JSON.parse(l));
}

const tc = (name, args = "{}") => ({ id: `${name}-id`, type: "function", function: { name, arguments: args } });

// mock LlmAdapter：依 script 逐 iteration 回 tool_calls，最後回無 tool_calls 收尾。
function mockAdapter(script) {
  let i = 0;
  return {
    async chat() {
      const step = script[i++];
      if (!step || step.stop) return { message: { role: "assistant", content: "done" }, stopReason: "stop" };
      return { message: { role: "assistant", content: "", tool_calls: step.tool_calls }, stopReason: "tool_calls" };
    },
  };
}
const mockPool = { async callTool(name) { return { content: [{ type: "text", text: `out:${name}` }], isError: false }; } };

// ── BC-6：redactArgs ───────────────────────────────────────────────────────
{
  const r = redactArgs({ command: "ls /home/user", apiKey: "sk-xxx", token: "abc", authorization: "Bearer y" });
  if (r.apiKey === "[REDACTED]" && r.token === "[REDACTED]" && r.authorization === "[REDACTED]" && r.command === "ls /home/user") {
    ok("BC-6 key-name blacklist redacts secrets, keeps path");
  } else fail("BC-6 key-name blacklist", JSON.stringify(r));

  const r2 = redactArgs({ command: "curl -H 'Authorization: Bearer sk-live-123' https://x" });
  if (typeof r2.command === "string" && r2.command.includes("[REDACTED]") && !r2.command.includes("sk-live-123")) {
    ok("BC-6 shell command value-level scrub");
  } else fail("BC-6 shell scrub", JSON.stringify(r2));
}

// ── BC-5：fail-silent（寫入失敗不拋）─────────────────────────────────────────
{
  const good = process.env.BRIDGE_OBSERVATIONS_PATH;
  // 指向一個「目錄」當檔案路徑 → appendFileSync 應 EISDIR；observer 必須吞掉。
  process.env.BRIDGE_OBSERVATIONS_PATH = OBS_DIR;
  let threw = false;
  try {
    const ret = recordSeqObservation({ name: "x", status: "completed", sessionId: "s", precedingTools: [] });
    if (ret !== undefined) threw = true; // 應回 void
  } catch { threw = true; }
  process.env.BRIDGE_OBSERVATIONS_PATH = good;
  if (!threw) ok("BC-5 fail-silent: write error neither throws nor returns value");
  else fail("BC-5 fail-silent", "recordSeqObservation threw or returned non-void on bad path");
}

// ── BC-1a：Tier B precedingTools = loop-local 發起序（非進 loop 前快照）──────────
{
  resetObs();
  const messages = [];
  await runToolLoop(
    mockAdapter([{ tool_calls: [tc("toolA")] }, { tool_calls: [tc("toolB")] }, { stop: true }]),
    mockPool, messages, [], { observe: { sessionId: "bc1a" } },
  );
  const obs = readObs();
  const a = obs.find((o) => o.name === "toolA");
  const b = obs.find((o) => o.name === "toolB");
  if (a && b && a.source === "rich" && b.source === "rich" &&
      a.precedingTools.length === 0 &&
      b.precedingTools.includes("toolA") &&
      b.precedingToolsSemantics === "exec-order") {
    ok("BC-1a rich precedingTools reflect exec-order (toolA precedes toolB)");
  } else fail("BC-1a exec-order precedingTools", JSON.stringify(obs));
}

// ── BC-7：rich 記 RTK rewrite 前的原始 args.command ─────────────────────────
{
  resetObs();
  const messages = [];
  await runToolLoop(
    mockAdapter([{ tool_calls: [tc("shell", JSON.stringify({ command: "git status" }))] }, { stop: true }]),
    mockPool, messages, [], { observe: { sessionId: "bc7" } },
  );
  const obs = readObs();
  const shell = obs.find((o) => o.name === "shell");
  if (shell && shell.args && shell.args.command === "git status") {
    ok("BC-7 rich records pre-RTK original command (not 'rtk git status')");
  } else fail("BC-7 pre-RTK snapshot", JSON.stringify(obs));
}

// ── BC-2：seq schema（completion-order-approx、無 args/output）────────────────
{
  resetObs();
  recordSeqObservation({ name: "grep", status: "completed", sessionId: "acp1", chatId: 5, precedingTools: ["glob"] });
  const obs = readObs();
  const o = obs[0];
  if (obs.length === 1 && o.source === "seq" && o.name === "grep" && o.status === "completed" &&
      o.precedingToolsSemantics === "completion-order-approx" &&
      o.args === undefined && o.output === undefined && o.isError === undefined) {
    ok("BC-2 seq observation: completion-order-approx, no args/output");
  } else fail("BC-2 seq schema", JSON.stringify(obs));
}

// ── BC-8：跨 turn 不污染 combo（turn marker 介於兩 turn 工具名之間）────────────
{
  // 模擬 sessionManager 對 _recentToolNames 的維護：tool_call push、resetTurn push marker。
  let recent = [];
  recent = appendToolName(recent, "toolA");          // turn1 tool
  if (recent.length) recent = appendToolName(recent, TURN_MARKER); // resetTurn（不清空）
  recent = appendToolName(recent, "toolB");          // turn2 tool
  const iA = recent.indexOf("toolA");
  const iM = recent.indexOf(TURN_MARKER);
  const iB = recent.indexOf("toolB");
  if (iA >= 0 && iM > iA && iB > iM) {
    ok("BC-8 turn marker separates cross-turn tools (toolA < TURN < toolB)");
  } else fail("BC-8 turn marker", JSON.stringify(recent));
}

// ── 收尾 ───────────────────────────────────────────────────────────────────
rmSync(OBS_DIR, { recursive: true, force: true });
const failed = results.filter((r) => !r.pass);
console.log(`\n${results.length - failed.length}/${results.length} passed`);
process.exit(failed.length ? 1 : 0);

