/**
 * Tool-Usage Observer — Phase 1：observation 寫入層
 *
 * 把 tool 使用落盤成結構化 JSONL（observations.jsonl），供 Phase 2 的
 * instinct-evolve analyzer 萃取 skill。本檔是「唯一寫入收斂點」：負責
 * schema 組裝、脫敏、截斷、size cap、fail-silent，零業務邏輯外洩。
 *
 * 雙層訊號（兩條 Provider 路徑都收）：
 *  - Tier A（seq）：sessionManager 在 tool_call_update 寫，僅 ACP 路徑。
 *    只有 name+status+precedingTools，且 precedingTools 是「完成順序近似」
 *    （ACP 進程外並行跑 tool，update 到達序 ≠ 發起序）→ 標
 *    precedingToolsSemantics:"completion-order-approx"，避免 Phase 2 誤當發起序。
 *  - Tier B（rich）：tool-loop 在 executeToolCalls 內寫，僅 DirectProvider。
 *    含 args（脫敏）+output（截斷）+isError，precedingTools 為 loop-local 發起序
 *    → precedingToolsSemantics:"exec-order"。
 *
 * fail-silent：寫入失敗只 console.error，絕不向上拋（不得中斷 tool loop / session）。
 */
import { appendFileSync, existsSync, mkdirSync, statSync } from "node:fs";
import { dirname, join } from "node:path";
import { config } from "./config.js";

// ─── 常數 ────────────────────────────────────────────────────────────────

/** turn 邊界哨兵。resetTurn 時 push，Phase 2 analyzer 見此即切斷 combo（不跨 turn）。 */
export const TURN_MARKER = " TURN ";

/** precedingTools 滾動長度上限（含 turn marker，避免長駐 session 無界增長）。 */
const MAX_RECENT = 8;

/** observations.jsonl 體積上限；超過即安靜停寫（Phase 1 不滾動，Phase 2 補 rotate）。 */
const OBS_MAX_BYTES = 32 * 1024 * 1024;

/** 單筆 rich output 的 hard cap。observer 自帶，不借 tool-loop 的 maxToolResultChars（非 local 時為 undefined=不截斷）。 */
const OBS_MAX_OUTPUT_CHARS = 8 * 1024;

/** 脫敏：key 名命中即把值替為 [REDACTED]。 */
const SECRET_KEY_RE = /token|key|secret|password|authorization|auth/i;

/** observations.jsonl 預設路徑（測試可用 BRIDGE_OBSERVATIONS_PATH 覆蓋）。 */
export const OBSERVATIONS_PATH = join(config.memoryDir, "observations.jsonl");

// ─── 型別 ────────────────────────────────────────────────────────────────

export type PrecedingSemantics = "exec-order" | "completion-order-approx";

export interface Observation {
  ts: string;
  source: "seq" | "rich";
  name: string;
  sessionId: string;
  chatId?: number;
  precedingTools: string[];
  precedingToolsSemantics: PrecedingSemantics;
  /** seq only */
  status?: "completed" | "failed";
  /** rich only — 經 redactArgs。 */
  args?: Record<string, unknown>;
  /** rich only — 經截斷。 */
  output?: string;
  /** rich only */
  isError?: boolean;
}

export interface SeqObservationInput {
  name: string;
  status: "completed" | "failed";
  sessionId: string;
  chatId?: number;
  precedingTools: string[];
}

export interface RichObservationInput {
  name: string;
  args: Record<string, unknown>;
  output: string;
  isError: boolean;
  sessionId: string;
  chatId?: number;
  precedingTools: string[];
}

// ─── 內部工具 ─────────────────────────────────────────────────────────────

/** 寫入路徑：測試覆蓋優先，否則用 config.memoryDir 下的預設檔。 */
function observationsPath(): string {
  return process.env.BRIDGE_OBSERVATIONS_PATH || OBSERVATIONS_PATH;
}

/** shell command 內嵌 secret 的 best-effort 清除（不合約化、不宣稱無洩漏）。 */
function scrubSecretsInText(s: string): string {
  return s
    .replace(/Bearer\s+\S+/gi, "Bearer [REDACTED]")
    .replace(/-p\s*\S+/g, "-p[REDACTED]")
    .replace(/\b(api[_-]?key|key|token|secret|password)\s*=\s*\S+/gi, "$1=[REDACTED]");
}

/**
 * 脫敏 args（best-effort，export 供測試）。
 * - key 名命中 SECRET_KEY_RE → 值替為 [REDACTED]。
 * - command 字串值（shell tool 最高頻）→ 額外跑 value-level regex。
 * ⚠️ 已知限制：擋不住「值是 secret 但 key 名無關鍵字」者。不寫成綠燈契約。
 */
export function redactArgs(args: Record<string, unknown>): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(args)) {
    if (SECRET_KEY_RE.test(k)) {
      out[k] = "[REDACTED]";
    } else if (k === "command" && typeof v === "string") {
      out[k] = scrubSecretsInText(v);
    } else {
      out[k] = v;
    }
  }
  return out;
}

function truncate(s: string, max: number): string {
  return s.length > max ? s.slice(0, max) + `\n...[truncated ${s.length - max} chars]` : s;
}

/**
 * 唯一落盤點。整段 try/catch 包覆（涵蓋 schema 組裝/脫敏/同步寫入的所有拋錯），
 * fail-silent。沿用 event-log.ts 的 mkdirSync+appendFileSync 範式。
 */
function appendObservation(obs: Observation): void {
  try {
    const target = observationsPath();
    // size cap：超過上限安靜停寫（不滾動、不刪除）
    if (existsSync(target) && statSync(target).size > OBS_MAX_BYTES) return;
    const dir = dirname(target);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    appendFileSync(target, JSON.stringify(obs) + "\n", "utf-8");
  } catch (err) {
    // observation 是旁路訊號，寫入失敗絕不影響主流程
    console.error("[tool-observer] failed to write observation:", err);
  }
}

// ─── 公開 API ─────────────────────────────────────────────────────────────

/** Tier A（ACP 路徑序列訊號）。fire-and-forget。 */
export function recordSeqObservation(input: SeqObservationInput): void {
  appendObservation({
    ts: new Date().toISOString(),
    source: "seq",
    name: input.name,
    status: input.status,
    sessionId: input.sessionId,
    chatId: input.chatId,
    precedingTools: input.precedingTools,
    precedingToolsSemantics: "completion-order-approx",
  });
}

/** Tier B（DirectProvider rich 訊號）。fire-and-forget。 */
export function recordRichObservation(input: RichObservationInput): void {
  appendObservation({
    ts: new Date().toISOString(),
    source: "rich",
    name: input.name,
    sessionId: input.sessionId,
    chatId: input.chatId,
    precedingTools: input.precedingTools,
    precedingToolsSemantics: "exec-order",
    args: redactArgs(input.args),
    output: truncate(input.output, OBS_MAX_OUTPUT_CHARS),
    isError: input.isError,
  });
}

/**
 * 把工具名（或 turn marker）push 進 rolling 序列並維持上限。
 * 兩條路徑共用此 helper 保證 cap 一致（避免無界增長）。
 */
export function appendToolName(recent: string[], name: string, max = MAX_RECENT): string[] {
  recent.push(name);
  const overflow = recent.length - max;
  if (overflow > 0) recent.splice(0, overflow);
  return recent;
}

