 * 「擋不住所有內嵌 secret」的誠實邊界，不為了它毀損正常指令）。
 */
function scrubSecretsInText(s: string): string {
  return s
    .replace(/Bearer\s+\S+/gi, "Bearer [REDACTED]")
    .replace(/\b(api[_-]?key|key|token|secret|password)\s*=\s*\S+/gi, "$1=[REDACTED]");
}

/** 單一值脫敏：key 名命中即整值替換；command 字串跑 scrub；object/array 在深度內遞迴。 */
function redactValue(key: string | undefined, v: unknown, depth: number): unknown {
  // key 名命中優先於一切（含巢狀內層）——R-3：{env:{API_KEY}} 的內層 key 也要脫。
  if (key && SECRET_KEY_RE.test(key)) return "[REDACTED]";
  if (key === "command" && typeof v === "string") return scrubSecretsInText(v);
  if (depth >= MAX_REDACT_DEPTH) return v; // 深度上限：停止下探，原值保留（不再 mutate）
  if (Array.isArray(v)) return v.map((item) => redactValue(undefined, item, depth + 1));
  if (v && typeof v === "object") return redactObject(v as Record<string, unknown>, depth + 1);
  return v;
}

function redactObject(obj: Record<string, unknown>, depth: number): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(obj)) {
    out[k] = redactValue(k, v, depth);
  }
  return out;
}

/**
 * 脫敏 args（best-effort，export 供測試）。深度受限遞迴：
 * - 任一層 key 名命中 SECRET_KEY_RE → 值替為 [REDACTED]（含巢狀 env/headers 內層）。
