// THROWAWAY (Phase 2 開工 gate · schema 適配性驗證 · 不入庫)
// 目的：用「shape 同真實 schema」的合成 observation，證明純統計（無 local LLM）
// 能從 Phase 1 落盤的 schema 萃出 ≥1 合理訊號。真實資料 gate 待 production 累積後重跑。

// ── 合成 observations（混 seq + rich，埋兩個刻意 pattern + 噪音）──────────────
const obs = [];
// pattern 1（seq combo）：glob → grep 重複 6 次（跨 turn，含 marker）
for (let i = 0; i < 6; i++) {
  obs.push({ source: "seq", name: "glob", status: "completed", precedingTools: [" TURN "], precedingToolsSemantics: "completion-order-approx" });
  obs.push({ source: "seq", name: "grep", status: "completed", precedingTools: [" TURN ", "glob"], precedingToolsSemantics: "completion-order-approx" });
}
// pattern 2（rich args）：shell git status 重複 7 次
for (let i = 0; i < 7; i++) {
  obs.push({ source: "rich", name: "shell", args: { command: "git status" }, isError: false, precedingTools: [], precedingToolsSemantics: "exec-order" });
}
// 噪音：散落的單發 tool
for (const n of ["read", "edit", "write", "ls"]) obs.push({ source: "seq", name: n, status: "completed", precedingTools: [], precedingToolsSemantics: "completion-order-approx" });

// ── 純統計 cluster ────────────────────────────────────────────────────────────
const MIN_OCC = 5;
// seq → combo（preceding 最後一個非 marker 工具 → 當前工具）
const combo = new Map();
for (const o of obs) {
  if (o.source !== "seq") continue;
  const prev = [...o.precedingTools].reverse().find((t) => t.trim() && t !== " TURN ");
  if (!prev) continue;
  const k = `${prev} → ${o.name}`;
  combo.set(k, (combo.get(k) ?? 0) + 1);
}
// rich → (name, command 動詞) 頻率
const richArgs = new Map();
for (const o of obs) {
  if (o.source !== "rich" || !o.args) continue;
  const verb = typeof o.args.command === "string" ? o.args.command.split(/\s+/).slice(0, 2).join(" ") : "(no-cmd)";
  const k = `${o.name}: ${verb}`;
  richArgs.set(k, (richArgs.get(k) ?? 0) + 1);
}

const signals = [...combo, ...richArgs].filter(([, c]) => c >= MIN_OCC).sort((a, b) => b[1] - a[1]);
console.log(`總 observations: ${obs.length}（seq ${obs.filter((o) => o.source === "seq").length} / rich ${obs.filter((o) => o.source === "rich").length}）`);
console.log(`達門檻（occ≥${MIN_OCC}）的訊號:`);
for (const [k, c] of signals) console.log(`  [${c}x] ${k}`);
console.log(signals.length >= 1 ? `\n✅ GATE PASS（schema 在純統計下可 cluster ≥1 訊號）` : `\n❌ GATE FAIL`);
process.exit(signals.length >= 1 ? 0 : 1);

